import java.io.*;
import java.util.*;

public class Main {
    static long[] solveCase(int n, long k, long[] dishes) {
        // your code here — return the rotated array of dish codes
        return dishes;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) sb.append(line).append(' ');
        StringTokenizer st = new StringTokenizer(sb.toString());
        int t = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            long k = Long.parseLong(st.nextToken());
            long[] dishes = new long[n];
            for (int i = 0; i < n; i++) dishes[i] = Long.parseLong(st.nextToken());
            long[] rotated = solveCase(n, k, dishes);
            for (int i = 0; i < n; i++) {
                out.append(rotated[i]);
                out.append(i + 1 < n ? ' ' : '\n');
            }
        }
        System.out.print(out);
    }
}

